(() => { 
                const root = {{DOM_CONTEXT}}; 
                if (!root) return;
                const wrap = root.querySelector('#tag-spec-wrap'); 
                if (!wrap) return;
                const container = root.parentElement || document.body;

                setInterval(() => {
                    let lifted = false;
                    if (container.querySelector('.lt-container')) {
                        lifted = true;
                    }
                    wrap.style.bottom = lifted ? '285px' : '115px'; 
                }, 100);
            })();

(() => { 
                const root = {{DOM_CONTEXT}}; 
                const textElement = root.querySelector('.news-text-v8');
                const container = root.querySelector('.news-container-v8');
                const wiper = root.querySelector('.wiper-v8');
                const dataEl = root.querySelector('#f-news-list');
                if(!textElement || !container || !wiper || !dataEl) return;

                let newsList = [];
                try { newsList = JSON.parse(dataEl.innerHTML); } catch(e) { newsList = ["BRAK DANYCH"]; }
                if(newsList.length === 0) newsList = ["BRAK WIADOMOŚCI"];

                let currentIndex = 0;
                let activeTimeouts = [];

                function adjustFontSize() {
                    const baseFontSize = 40;
                    const leftPadding = 170; 
                    const maxWidth = container.offsetWidth - (leftPadding + 20);
                    textElement.style.fontSize = baseFontSize + "px";
                    let currentWidth = textElement.scrollWidth - leftPadding;
                    if (currentWidth > maxWidth && currentWidth > 0) {
                        const newSize = (maxWidth / currentWidth) * baseFontSize;
                        textElement.style.fontSize = newSize + "px";
                    }
                }

                function runCycle() {
                    if(!document.contains(container)) return;
                    textElement.classList.remove('visible');
                    textElement.innerText = newsList[currentIndex];
                    adjustFontSize();

                    activeTimeouts.push(setTimeout(() => { if(!document.contains(container)) return; textElement.classList.add('visible'); }, 100));
                    activeTimeouts.push(setTimeout(() => {
                        if(!document.contains(container)) return;
                        textElement.classList.remove('visible');
                        activeTimeouts.push(setTimeout(() => {
                            if(!document.contains(container)) return;
                            wiper.className = 'wiper-v8 move-right';
                            activeTimeouts.push(setTimeout(() => {
                                if(!document.contains(container)) return;
                                wiper.className = 'wiper-v8 snap-back';
                                activeTimeouts.push(setTimeout(() => {
                                    if(!document.contains(container)) return;
                                    currentIndex = (currentIndex + 1) % newsList.length;
                                    runCycle();
                                }, 500));
                            }, 1000));
                        }, 400));
                    }, 4000));
                }
                runCycle();
                window.addEventListener('resize', adjustFontSize);
            })();

(() => { 
                const root = {{DOM_CONTEXT}};
                const tickerWrap = root.querySelector('.ticker-wrap-v8');
                const dataEl = root.querySelector('#f-crawl-list');
                if(!tickerWrap || !dataEl) return;

                let subNewsList = [];
                try { subNewsList = JSON.parse(dataEl.innerHTML); } catch(e) { subNewsList = []; }
                if(subNewsList.length === 0) return;

                let content = "";
                subNewsList.forEach(news => {
                    content += '<span class="separator-v8">BTB INFO</span>';
                    content += '<span class="news-item-v8">' + news + '</span>';
                });
                tickerWrap.innerHTML = content + content;
            })();
